import{_ as e,o as d,c as i,a2 as l}from"./chunks/framework.BnBoz4Zl.js";const h=JSON.parse('{"title":"安居建业 WorkBuddy 阅读指南｜从入门到岗位落地","titleTemplate":false,"description":"安居建业内部 WorkBuddy 阅读路线，从基础使用和第一项任务，到真实案例、工作流沉淀与岗位落地。","frontmatter":{"title":"安居建业 WorkBuddy 阅读指南｜从入门到岗位落地","titleTemplate":false,"description":"安居建业内部 WorkBuddy 阅读路线，从基础使用和第一项任务，到真实案例、工作流沉淀与岗位落地。","breadcrumbTitle":"阅读指南"},"headers":[],"relativePath":"reading-guide.md","filePath":"reading-guide.md","lastUpdated":1783915201000}'),o={name:"reading-guide.md"};function r(t,a,u,n,k,b){return d(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="安居建业-workbuddy-阅读指南-从入门到岗位落地" tabindex="-1">安居建业 WorkBuddy 阅读指南：从入门到岗位落地 <a class="header-anchor" href="#安居建业-workbuddy-阅读指南-从入门到岗位落地" aria-label="Permalink to &quot;安居建业 WorkBuddy 阅读指南：从入门到岗位落地&quot;">​</a></h1><p>这是一条面向安居建业新手、任务实践者和团队负责人的 WorkBuddy 学习路线。你不必从头背功能：先找到当前最接近的工作问题，完成一项真实任务，再沿着基础使用、实战案例、进阶系统和岗位落地逐步深入。</p><h2 id="workbuddy-新手入门路线" tabindex="-1">WorkBuddy 新手入门路线 <a class="header-anchor" href="#workbuddy-新手入门路线" aria-label="Permalink to &quot;WorkBuddy 新手入门路线&quot;">​</a></h2><p>从<a href="/anjian-workbuddy-bluebook-site/bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/">第一篇：先把 WorkBuddy 用起来</a>开始，依次完成：</p><ol><li>下载、安装和登录。</li><li>认识主界面、任务与工作区。</li><li>完成第一个可检查的任务。</li><li>加载一个真正用得上的 Skill。</li><li>再学习连接器、外部 API 与自动化任务。</li></ol><p>建议边读边做，不要只浏览截图。每完成一章，至少留下一个可复用的提示词、模板或操作记录。</p><h2 id="按真实任务选择-workbuddy-教程" tabindex="-1">按真实任务选择 WorkBuddy 教程 <a class="header-anchor" href="#按真实任务选择-workbuddy-教程" aria-label="Permalink to &quot;按真实任务选择 WorkBuddy 教程&quot;">​</a></h2><p>直接进入<a href="/anjian-workbuddy-bluebook-site/bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/">第二篇：案例篇</a>，按问题选择章节：</p><ul><li>处理 Word、Excel、PPT：第 11 章。</li><li>整理电脑文件：第 12 章。</li><li>远程控制电脑：第 13 章。</li><li>资讯、收藏、会议和投资：第 15～18 章。</li><li>AI 视频、自媒体和 GEO：第 19～21 章。</li></ul><p>案例跑通后，再回到第三篇，把你的做法整理为 Skill、自动化或多 Agent 系统。</p><h2 id="workbuddy-团队落地路线" tabindex="-1">WorkBuddy 团队落地路线 <a class="header-anchor" href="#workbuddy-团队落地路线" aria-label="Permalink to &quot;WorkBuddy 团队落地路线&quot;">​</a></h2><p>重点阅读<a href="/anjian-workbuddy-bluebook-site/bluebook/第三篇 进阶篇：把案例变成自己的工作系统/">第三篇：进阶篇</a>与<a href="/anjian-workbuddy-bluebook-site/bluebook/第四篇 岗位与行业落地/">第四篇：岗位与行业落地</a>。</p><p>团队实践建议同时记录：</p><ul><li>输入资料和权限边界。</li><li>任务拆解方式和失败回退。</li><li>交付物的验收标准。</li><li>可以复用的 Skill、模板和自动化。</li><li>哪些步骤必须由人确认。</li></ul><h2 id="提交内部共创案例" tabindex="-1">提交内部共创案例 <a class="header-anchor" href="#提交内部共创案例" aria-label="Permalink to &quot;提交内部共创案例&quot;">​</a></h2><p>欢迎阅读<a href="/anjian-workbuddy-bluebook-site/community/contributing">共创案例规范</a>。真实案例应先完成脱敏、权限和边界检查，再进入逐章筛选与编写流程。</p>',16)])])}const p=e(o,[["render",r]]);export{h as __pageData,p as default};
